{"content":"package kotlinx.datetime.test

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

class FixesTest {
    @Test
    fun testLocalDateParseLeadingZeroes() {
        // +00000000000002022-07-16
        val date = LocalDate.parse("+00000000000002022-07-16")
        assertEquals(LocalDate(2022, 7, 16), date)
    }

    @Test
    fun testLocalDateTimeParseLeadingZeroes() {
        val dateTime = LocalDateTime.parse("+00000000000002022-07-16T12:34:56")
        assertEquals(LocalDateTime(2022, 7, 16, 12, 34, 56), dateTime)
    }

    @Test
    fun testDateTimePeriodParseP() {
        assertFailsWith<DateTimeFormatException> {
            DateTimePeriod.parse("P")
        }
        assertFailsWith<DateTimeFormatException> {
            DateTimePeriod.parse("+P")
        }
        assertFailsWith<DateTimeFormatException> {
            DateTimePeriod.parse("-P")
        }
    }

    @Test
    fun testDateTimePeriodParseValid() {
        assertEquals(DatePeriod(days = 0), DateTimePeriod.parse("P0D"))
        assertEquals(DatePeriod(years = 1), DateTimePeriod.parse("P1Y"))
    }
}
